func totalSubs(counts map[string]int) int {
	n := 0
	for _, c := range counts {
		n += c
	}
	return n
}

func topicPublished(m tavern.BrokerMetrics, topic string) int64 {
	if ts, ok := m.TopicStats[topic]; ok {
		return ts.Published
	}
	return 0
}

func topicDropped(m tavern.BrokerMetrics, topic string) int64 {
	if ts, ok := m.TopicStats[topic]; ok {
		return ts.Dropped
	}
	return 0
}

func topicPeak(m tavern.BrokerMetrics, topic string) int {
	if ts, ok := m.TopicStats[topic]; ok {
		return ts.PeakSubscribers
	}
	return 0
}

func topicThroughput(data ObservatoryData, topic string) float64 {
	if data.ObsSnap == nil {
		return 0
	}
	if to, ok := data.ObsSnap.Topics[topic]; ok {
		return to.Throughput
	}
	return 0
}

func formatLatency(data ObservatoryData, topic string) string {
	if data.ObsSnap == nil {
		return "-"
	}
	if to, ok := data.ObsSnap.Topics[topic]; ok && to.PublishLatency.Count > 0 {
		return fmt.Sprintf("%s", to.PublishLatency.P99.Round(time.Microsecond))
	}
	return "-"
}

func obsDropClass(drops int64) string {
	switch {
	case drops > 100:
		return "text-error font-semibold"
	case drops > 10:
		return "text-warning"
	default:
		return ""
	}
}

func tierBadgeClass(tier int) string {
	switch tier {
	case 0:
		return "badge-success"
	case 1:
		return "badge-warning"
	case 2:
		return "badge-accent"
	case 3:
		return "badge-error"
	default:
		return "badge-ghost"
	}
}

